Having played around with the code, I found that the case i mentioned didnt worked correctly
- **Round 0**:
    - Max height: 273
    - After sync, tip is at 273
- **Round 1**:
    - Max height: 446 (273 + 173)
    - Sync fails at height 310
- **Round 2**:
	- The first batch starts at 273, however, it should be 304 (the previous round synced one batch)

    This happens because CustomAppend() returns false and the process is stpped before the following branch is reached
    ```c++
    if (m_interrupt) {
        LogInfo("%s: m_interrupt set; exiting ThreadSync", GetName());
	     SetBestBlockIndex(pindex);
        Commit();
        return;
    }
	```
Below is the code to reproduce the issue:

```c++
// Extend BlockFilterIndex to create a custom test function CustomAppend
class BlockFilterIndexTest : public BlockFilterIndex
{
public:
    BlockFilterIndexTest(std::unique_ptr<interfaces::Chain> chain, BlockFilterType filter_type, size_t n_cache_size, bool f_memory) :
        BlockFilterIndex(std::move(chain), filter_type, n_cache_size, f_memory) {}

    // Override CustomAppend to simulate an error during append at a specific block height
    bool CustomAppend(CDBBatch& batch, const interfaces::BlockInfo& block) override
    {
        if (block.height == 290) {
            return false;
        }
        return BlockFilterIndex::CustomAppend(batch, block);
    }
};

// Ensure the initial sync batch window behaves as expected.
// Tests sync from the genesis block and from a higher block to mimic a restart.
// Note: Test runs in /tmp by default, which is usually cached, so timings are not
// a meaningful benchmark (use -testdatadir to run it elsewhere).
BOOST_FIXTURE_TEST_CASE(initial_sync_batch_window, BuildChainTestingSetup)
{
    constexpr int MINE_BLOCKS = 173;
    constexpr int BATCH_SIZE = 30;

    int expected_tip = 100; // pre-mined blocks
    for (int round = 0; round < 3; round++) { // two additional rounds to test sync from genesis and from a higher block
        mineBlocks(MINE_BLOCKS); // Generate blocks
        const int tip_height = WITH_LOCK(::cs_main, return m_node.chainman->ActiveChain().Height());
        BOOST_REQUIRE(tip_height == MINE_BLOCKS + expected_tip);
        expected_tip = tip_height;

        BlockFilterIndexTest filter_index(interfaces::MakeChain(m_node), BlockFilterType::BASIC, 1 << 20, /*f_memory=*/false);
        filter_index.SetProcessingBatchSize(BATCH_SIZE);
        BOOST_REQUIRE(filter_index.Init());
        BOOST_CHECK(!filter_index.BlockUntilSyncedToCurrentChain());

        // Ensure we can sync up to the tip
        const auto& summary_pre{filter_index.GetSummary()};
        // breakpoint here for following gdb ouptut
        filter_index.Sync();
        if (round == 1) { continue; }
        const auto& summary{filter_index.GetSummary()};
        BOOST_CHECK(summary.synced);
```

